// Obtener la lista de productos del nodo anterior
const productos = $input.first().json.productos;

let subtotalFactura = 0;

// Generar dinámicamente las filas de la tabla
let filasHTML = "";

for (const p of productos) {
  // 1. Total bruto de la fila (sin descuentos)
  const precioTotalFila = p.precio_unitario * p.unidades;

  // 2. Limpiamos y calculamos la bonificación (ej. "12,00%" -> 0.12)
  let bonificacionPorcentaje = 0;

  if (p.bonificacion) {
      if (typeof p.bonificacion === 'string') {
          bonificacionPorcentaje = parseFloat(p.bonificacion.replace(',', '.').replace('%', '')) / 100 || 0;
      } else if (typeof p.bonificacion === 'number') {
          bonificacionPorcentaje = p.bonificacion > 1 ? p.bonificacion / 100 : p.bonificacion;
      }
  }

  // 3. Calculamos el descuento en pesos y se lo restamos al total de esta fila
  const descuentoFila = precioTotalFila * bonificacionPorcentaje;
  const netoFila = precioTotalFila - descuentoFila;

  subtotalFactura += netoFila;

  // 4. Armamos el HTML. 
  // Opcional: Le agregué un textito avisando si tiene descuento en la descripción
  let textoDescuento = bonificacionPorcentaje > 0 ? ` <small>(Desc. ${p.bonificacion})</small>` : '';

  filasHTML += `
    <tr>
      <td>${p.descripcion}${textoDescuento}</td>
      <td>${p.unidades}</td>
      <td>${p.precio_unitario.toLocaleString('es-AR')}</td>
      <td>${precioTotalFila.toLocaleString('es-AR')}</td>
    </tr>
  `;
}

// --- CÁLCULOS GLOBALES ---


const porcentajeIVA = 0; // Lo dejamos en 0 para que no sume IVA
const ivaTotalFactura = subtotalFactura * porcentajeIVA;

// Total final
const totalFinalFactura = subtotalFactura + ivaTotalFactura;

// Devolver el HTML generado y los totales formateados
return [{ 
  json: { 
    filasHTML: filasHTML,
    subtotalFormateado: subtotalFactura.toLocaleString('es-AR'),
    ivaFormateado: ivaTotalFactura.toLocaleString('es-AR'),
    totalFinalFormateado: totalFinalFactura.toLocaleString('es-AR')
  }
}];

function toBase64(str) {
  let chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=';
  let output = '';
  let i = 0;
  while (i < str.length) {
    let c1 = str.charCodeAt(i++);
    let c2 = str.charCodeAt(i++);
    let c3 = str.charCodeAt(i++);

    let e1 = c1 >> 2;
    let e2 = ((c1 & 3) << 4) | (c2 >> 4);
    let e3 = ((c2 & 15) << 2) | (c3 >> 6);
    let e4 = c3 & 63;

    if (isNaN(c2)) e3 = e4 = 64;
    else if (isNaN(c3)) e4 = 64;

    output += chars.charAt(e1) + chars.charAt(e2) + chars.charAt(e3) + chars.charAt(e4);
  }
  return output;
}

